import csv, io
raw = "id,nombre\nC001,Ana\nC002\n"  # fila corta
reader = csv.DictReader(io.StringIO(raw))
for row in reader:
    if None in row.values() or row.get("nombre") in (None, ""):
        print("quarantine", row)
    else:
        print("clean", row)

def reason_for(row):
    if "id" not in row:
        return "missing_id"
    if row.get("monto") is None:
        return "missing_monto"
    return None
print(reason_for({}), reason_for({"id":"C1"}))

