def reconcile(n_in, n_clean, n_q):
    if n_in != n_clean + n_q:
        raise SystemExit(1)
    return "ok"
print(reconcile(5, 4, 1))

def should_publish(ok_reconcile):
    return bool(ok_reconcile)
print(should_publish(True), should_publish(False))

